// ═══════════════════════════════════════════════════════════════════
// App.tsx – Main application layout with resize handles,
// keyboard shortcuts, and modal integration
// ═══════════════════════════════════════════════════════════════════
import { useState, useRef, useEffect, useCallback } from 'react';
import { GanttProvider, useGantt } from './store/GanttContext';
import Ribbon from './components/Ribbon';
import GanttTable from './components/GanttTable';
import GanttTimeline from './components/GanttTimeline';
import TaskForm from './components/TaskForm';
import ActivityDetailPanel from './components/ActivityDetailPanel';
import ResourceSheet from './components/ResourceSheet';
import ActivityModal from './components/modals/ActivityModal';
import ProjectModal from './components/modals/ProjectModal';
import LinkModal from './components/modals/LinkModal';
import SupabaseModal from './components/modals/SupabaseModal';
import SaveProgressModal from './components/modals/SaveProgressModal';
import BaselineModal from './components/modals/BaselineModal';
import CalendarModal from './components/modals/CalendarModal';
import CheckThresholdsModal from './components/modals/CheckThresholdsModal';
import FilterModal from './components/modals/FilterModal';
import SCurveChart from './components/SCurveChart';
import TaskUsageGrid from './components/TaskUsageGrid';
import ResourceUsageTable from './components/ResourceUsageTable';
import ResourceUsageGrid from './components/ResourceUsageGrid';
import ResourceForm from './components/ResourceForm';
import WBSOrgChartView from './components/WBSOrgChartView';
import ModuleTabs, { type ModuleId } from './components/ModuleTabs';
import InicioPage from './components/modules/InicioPage';
import LookAheadPage from './components/modules/LookAheadPage';
import DashboardPage from './components/modules/DashboardPage';
import ConfigPage from './components/modules/ConfigPage';
import WhatIfPage from './components/modules/WhatIfPage';
import RiskAnalysisPage from './components/modules/RiskAnalysisPage';
import ProjectsPage from './components/modules/ProjectsPage';
import { PortfolioProvider, usePortfolio } from './store/PortfolioContext';
import { AuthProvider, useAuth } from './store/AuthContext';
import LoginPage from './components/modules/LoginPage';
import { newActivity } from './utils/cpm';
import { autoId } from './utils/helpers';
import { saveToSupabase, loadFromSupabase, createSupabaseProject } from './utils/supabaseSync';
import { supabase } from './lib/supabase';

/* eslint-disable @typescript-eslint/no-explicit-any */
/** Restore ISO-string dates back to Date objects in a saved project snapshot */
function restoreDatesFromSaved(saved: any): any {
  if (saved.projStart && typeof saved.projStart === 'string') saved.projStart = new Date(saved.projStart);
  if (saved.statusDate && typeof saved.statusDate === 'string') saved.statusDate = new Date(saved.statusDate);
  if (saved.activities) {
    saved.activities = saved.activities.map((a: any) => ({
      ...a,
      ES: a.ES ? new Date(a.ES) : null,
      EF: a.EF ? new Date(a.EF) : null,
      LS: a.LS ? new Date(a.LS) : null,
      LF: a.LF ? new Date(a.LF) : null,
      blES: a.blES ? new Date(a.blES) : null,
      blEF: a.blEF ? new Date(a.blEF) : null,
      _remES: a._remES ? new Date(a._remES) : null,
      _remEF: a._remEF ? new Date(a._remEF) : null,
      collapsed: undefined,
      baselines: (a.baselines || []).map((bl: any) => bl ? {
        ...bl,
        ES: bl.ES ? new Date(bl.ES) : null,
        EF: bl.EF ? new Date(bl.EF) : null,
      } : null),
    }));
  }
  return saved;
}

/** Serialize GanttState to a plain JSON-safe object for localStorage */
function serializeGanttState(state: any): any {
  return {
    projName: state.projName,
    projStart: state.projStart instanceof Date ? state.projStart.toISOString() : state.projStart,
    defCal: state.defCal,
    statusDate: state.statusDate instanceof Date ? state.statusDate.toISOString() : state.statusDate,
    activities: state.activities.map((a: any) => ({
      ...a,
      ES: a.ES ? (a.ES instanceof Date ? a.ES.toISOString() : a.ES) : null,
      EF: a.EF ? (a.EF instanceof Date ? a.EF.toISOString() : a.EF) : null,
      LS: a.LS ? (a.LS instanceof Date ? a.LS.toISOString() : a.LS) : null,
      LF: a.LF ? (a.LF instanceof Date ? a.LF.toISOString() : a.LF) : null,
      blES: a.blES ? (a.blES instanceof Date ? a.blES.toISOString() : a.blES) : null,
      blEF: a.blEF ? (a.blEF instanceof Date ? a.blEF.toISOString() : a.blEF) : null,
      _remES: a._remES ? (a._remES instanceof Date ? a._remES.toISOString() : a._remES) : null,
      _remEF: a._remEF ? (a._remEF instanceof Date ? a._remEF.toISOString() : a._remEF) : null,
      baselines: (a.baselines || []).map((bl: any) => bl ? {
        ...bl,
        ES: bl.ES ? (bl.ES instanceof Date ? bl.ES.toISOString() : bl.ES) : null,
        EF: bl.EF ? (bl.EF instanceof Date ? bl.EF.toISOString() : bl.EF) : null,
      } : null),
    })),
    resourcePool: state.resourcePool,
    progressHistory: state.progressHistory,
    ppcHistory: state.ppcHistory,
    leanRestrictions: state.leanRestrictions,
    scenarios: state.scenarios ? state.scenarios.map((sc: any) => ({
      ...sc,
      activities: (sc.activities || []).map((a: any) => ({
        ...a,
        ES: a.ES ? (a.ES instanceof Date ? a.ES.toISOString() : a.ES) : null,
        EF: a.EF ? (a.EF instanceof Date ? a.EF.toISOString() : a.EF) : null,
        LS: a.LS ? (a.LS instanceof Date ? a.LS.toISOString() : a.LS) : null,
        LF: a.LF ? (a.LF instanceof Date ? a.LF.toISOString() : a.LF) : null,
        blES: a.blES ? (a.blES instanceof Date ? a.blES.toISOString() : a.blES) : null,
        blEF: a.blEF ? (a.blEF instanceof Date ? a.blEF.toISOString() : a.blEF) : null,
      })),
    })) : [],
    customCalendars: state.customCalendars,
    customFilters: state.customFilters,
    filtersMatchAll: state.filtersMatchAll,
    activeBaselineIdx: state.activeBaselineIdx,
    showProjRow: state.showProjRow,
    riskState: state.riskState,
    columnViews: state.columnViews,
    _hiddenOtherData: state._hiddenOtherData,
  };
}
/* eslint-enable @typescript-eslint/no-explicit-any */

function AppInner() {
  const { state, dispatch } = useGantt();
  const { state: pState, dispatch: pDispatch, saveProjectState, loadProjectState } = usePortfolio();
  const [formH, setFormH] = useState(200);
  const [resizing, setResizing] = useState<'v' | 'h' | null>(null);
  const [activeModule, setActiveModule] = useState<ModuleId>(() => {
    const saved = localStorage.getItem('gantt_active_module');
    const valid: ModuleId[] = ['inicio', 'projects', 'gantt', 'lookAhead', 'dashboard', 'whatIf', 'risk', 'config'];
    return saved && valid.includes(saved as ModuleId) ? saved as ModuleId : 'projects';
  });

  const [showRecoveryModal, setShowRecoveryModal] = useState(false);
  const [newRecoveryPassword, setNewRecoveryPassword] = useState('');
  const [recoveryLoading, setRecoveryLoading] = useState(false);

  const hasActiveProject = !!pState.activeProjectId;
  const containerRef = useRef<HTMLDivElement>(null);

  // Theme toggle on body
  useEffect(() => {
    const html = document.documentElement;
    if (state.lightMode) html.classList.add('light');
    else html.classList.remove('light');
  }, [state.lightMode]);

  useEffect(() => {
    const { data: { subscription } } = supabase.auth.onAuthStateChange((event: string, _session: unknown) => {
      if (event === 'PASSWORD_RECOVERY') {
        setShowRecoveryModal(true);
      }
    });
    return () => subscription.unsubscribe();
  }, []);

  const handleUpdatePassword = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newRecoveryPassword || newRecoveryPassword.length < 6) {
      alert("La contraseña debe tener al menos 6 caracteres.");
      return;
    }
    setRecoveryLoading(true);
    const { error } = await supabase.auth.updateUser({ password: newRecoveryPassword });
    setRecoveryLoading(false);

    if (error) {
      alert('Error al actualizar la contraseña: ' + error.message);
    } else {
      alert('Contraseña actualizada exitosamente.');
      setShowRecoveryModal(false);
      setNewRecoveryPassword('');
    }
  };

  const loadDemoData = useCallback(() => {
    const d = state.defCal;
    const acts = [
      { ...newActivity('PROY', d), name: 'Mi Proyecto', type: 'summary' as const, lv: -1, _isProjRow: true },
      { ...newActivity('A1000', d), name: 'Resumen', type: 'summary' as const, lv: 0, dur: 0 },
      { ...newActivity('A1010', d), name: 'Excavación', type: 'task' as const, lv: 1, dur: 10, remDur: null, res: 'Panexero', work: 500 },
      { ...newActivity('A1020', d), name: 'Excavación', type: 'task' as const, lv: 1, dur: 6, remDur: null, preds: [{ id: 'A1010', type: 'FS' as const, lag: 0 }], res: 'Panexero; Carpintero', work: 1500 },
      { ...newActivity('A1030', d), name: 'Actividad 3', type: 'task' as const, lv: 1, dur: 21, remDur: null, preds: [{ id: 'A1010', type: 'SS' as const, lag: 0 }], res: 'Carpintero; Marinero', work: 0 },
      { ...newActivity('A1040', d), name: 'Resumen 2', type: 'summary' as const, lv: 0, dur: 0 },
      { ...newActivity('A1050', d), name: 'Actividad 4', type: 'task' as const, lv: 1, dur: 5, remDur: null, preds: [{ id: 'A1000', type: 'FS' as const, lag: 0 }], res: 'Deivy', work: 2000 },
      { ...newActivity('A1060', d), name: 'Actividad 5', type: 'task' as const, lv: 1, dur: 5, remDur: null, preds: [{ id: 'A1000', type: 'FS' as const, lag: 0 }, { id: 'A1010', type: 'FS' as const, lag: 0 }], res: 'Alexander', work: 700 },
    ];
    dispatch({ type: 'SET_ACTIVITIES', activities: acts });
  }, [state.defCal, dispatch]);

  const saveTimeoutRef = useRef<number | null>(null);
  const switchingProjectRef = useRef(false); // guard: suppress auto-save during project switch
  const initialLoadingRef = useRef(true); // guard: suppress auto-save until initial Supabase load completes

  // 1. Initial Load – restore active project from localStorage FIRST (fast),
  //    then verify against Supabase (source of truth, overrides if it has data).
  useEffect(() => {
    const initApp = async () => {
      initialLoadingRef.current = true;
      const pid = typeof window !== 'undefined' ? localStorage.getItem('sb_current_project_id') : null;
      const activeId = pState.activeProjectId;

      // ── Step A: Quick-restore from localStorage (instant, avoids blank screen) ──
      let localLoaded = false;
      if (activeId) {
        const saved = loadProjectState(activeId);
        if (saved) {
          restoreDatesFromSaved(saved);
          dispatch({ type: 'LOAD_STATE', state: saved });
          localLoaded = true;
          console.log('[initApp] Quick-restored from localStorage:', activeId);
        }
      }

      // ── Step B: Verify / overlay from Supabase (async, source of truth) ──
      const sbPid = pid || (activeId ? pState.projects.find(p => p.id === activeId)?.supabaseId : null) || null;
      if (sbPid) {
        try {
          const data = await loadFromSupabase(sbPid);
          if (data.activities && data.activities.length) {
            // Supabase has real activity data → use it (more authoritative)
            if (data.projName) dispatch({ type: 'SET_PROJECT_CONFIG', config: { projName: data.projName, projStart: data.projStart, defCal: data.defCal, statusDate: data.statusDate || undefined, customFilters: data.customFilters || [], filtersMatchAll: data.filtersMatchAll !== undefined ? data.filtersMatchAll : true, _hiddenOtherData: data._hiddenOtherData } });
            if (data.resourcePool) dispatch({ type: 'SET_RESOURCES', resources: data.resourcePool });
            dispatch({ type: 'SET_ACTIVITIES', activities: data.activities });
            if (data.progressHistory) dispatch({ type: 'SET_PROGRESS_HISTORY', history: data.progressHistory });
            if (data.ppcHistory && data.ppcHistory.length) dispatch({ type: 'SET_PPC_HISTORY', history: data.ppcHistory });
            if (data.leanRestrictions && data.leanRestrictions.length) dispatch({ type: 'SET_LEAN_RESTRICTIONS', restrictions: data.leanRestrictions });
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            if ((data as any).scenarios && (data as any).scenarios.length) dispatch({ type: 'SET_SCENARIOS', scenarios: (data as any).scenarios });
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            if ((data as any).riskState) dispatch({ type: 'LOAD_RISK_STATE', riskState: (data as any).riskState });
            if (data.columnViews && data.columnViews.length) dispatch({ type: 'SET_COLUMN_VIEWS', views: data.columnViews });
            if (!pid) localStorage.setItem('sb_current_project_id', sbPid);
            console.log('[initApp] Loaded from Supabase:', sbPid);
            initialLoadingRef.current = false;
            return;
          }
          // Supabase project exists but has NO activities (possibly caught mid-save)
          if (localLoaded) {
            console.warn('[initApp] Supabase has no activities but localStorage does — keeping localStorage data; auto-save will heal Supabase');
            initialLoadingRef.current = false;
            return;
          }
          console.warn('[initApp] Supabase has no activities and no localStorage data');
        } catch (err) {
          console.warn('[initApp] Supabase load failed:', err);
          if (localLoaded) { initialLoadingRef.current = false; return; } // localStorage already restored, that's fine
        }
      }

      // ── Step C: If nothing loaded yet, we're done (localStorage already loaded above if available) ──
      if (localLoaded) { initialLoadingRef.current = false; return; }

      // ── Step D: Fallback – demo data only if no portfolio projects exist at all ──
      if (pState.projects.length === 0) {
        loadDemoData();
      }
      initialLoadingRef.current = false;
    };
    initApp();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // run once on mount — pState is synchronously available

  // 2. Auto-save on state changes (only if a project is already connected)
  useEffect(() => {
    if (!state.activities.length) return;
    if (switchingProjectRef.current) return; // suppress during project switch
    if (initialLoadingRef.current) return; // suppress until initial Supabase load completes
    const pid = localStorage.getItem('sb_current_project_id');
    if (!pid) return; // No auto-create — user must create/load a project first
    if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);
    saveTimeoutRef.current = window.setTimeout(async () => {
      if (switchingProjectRef.current) return; // re-check after timeout
      if (initialLoadingRef.current) return; // re-check after timeout
      const currentPid = localStorage.getItem('sb_current_project_id');
      if (!currentPid) return;
      try {
        const newId = await saveToSupabase(state, currentPid);
        if (newId && newId !== currentPid) localStorage.setItem('sb_current_project_id', newId);
        // Dual-write: also save to localStorage for beforeunload recovery
        if (pState.activeProjectId) {
          const snapshot = serializeGanttState(state);
          saveProjectState(pState.activeProjectId, snapshot);
        }
        console.log('Auto-saved to Supabase + localStorage');
      } catch (err) {
        console.error('Auto-save error:', err);
        // Still save to localStorage as fallback
        if (pState.activeProjectId) {
          try {
            const snapshot = serializeGanttState(state);
            saveProjectState(pState.activeProjectId, snapshot);
          } catch { }
        }
      }
    }, 800);
    return () => { if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current); };
  }, [state.activities, state.resourcePool, state.projName, state.projStart, state.defCal, state.statusDate, state.ppcHistory, state.leanRestrictions, state.progressHistory, state.scenarios, state.columnViews, state.customFilters, state.filtersMatchAll, state.riskState.riskEvents, state.riskState.distributions, state.riskState.simulationRuns, state.riskState.riskScoring, state.riskState.params, pState.activeProjectId, saveProjectState]);

  // 3. Listen to Supabase Events
  useEffect(() => {
    const handleLoad = async (e: Event) => {
      const customEvent = e as CustomEvent;
      const pid = customEvent.detail?.projectId;
      if (!pid) return;
      try {
        const data = await loadFromSupabase(pid);
        dispatch({ type: 'SET_PROJECT_CONFIG', config: { projName: data.projName, projStart: data.projStart, defCal: data.defCal, statusDate: data.statusDate || undefined, customFilters: data.customFilters || [], filtersMatchAll: data.filtersMatchAll !== undefined ? data.filtersMatchAll : true, _hiddenOtherData: data._hiddenOtherData } });
        dispatch({ type: 'SET_RESOURCES', resources: data.resourcePool || [] });
        dispatch({ type: 'SET_ACTIVITIES', activities: data.activities || [] });
        dispatch({ type: 'SET_PROGRESS_HISTORY', history: data.progressHistory || [] });
        if (data.ppcHistory && data.ppcHistory.length) dispatch({ type: 'SET_PPC_HISTORY', history: data.ppcHistory });
        if (data.leanRestrictions && data.leanRestrictions.length) dispatch({ type: 'SET_LEAN_RESTRICTIONS', restrictions: data.leanRestrictions });
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        if ((data as any).scenarios && (data as any).scenarios.length) dispatch({ type: 'SET_SCENARIOS', scenarios: (data as any).scenarios });
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        if ((data as any).riskState) dispatch({ type: 'LOAD_RISK_STATE', riskState: (data as any).riskState });
        if (data.columnViews && data.columnViews.length) dispatch({ type: 'SET_COLUMN_VIEWS', views: data.columnViews });
        localStorage.setItem('sb_current_project_id', pid);
        alert('Proyecto cargado exitosamente');
      } catch (err: unknown) {
        alert('Error al cargar proyecto: ' + (err instanceof Error ? err.message : String(err)));
      }
    };
    const handleForceSave = async (e?: Event) => {
      if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);
      const customEvent = e as CustomEvent | undefined;
      const silent = customEvent?.detail?.silent === true;
      const pid = localStorage.getItem('sb_current_project_id');
      if (!pid) {
        if (!silent) alert('No hay proyecto conectado. Cree o cargue un proyecto primero desde Configuración.');
        return;
      }
      try {
        const newId = await saveToSupabase(state, pid);
        if (newId && newId !== pid) localStorage.setItem('sb_current_project_id', newId);
        if (!silent) alert('Proyecto guardado exitosamente');
        else console.log('Silent save to Supabase completed');
      } catch (err: unknown) {
        if (!silent) alert('Error al guardar: ' + (err instanceof Error ? err.message : String(err)));
        else console.error('Silent save error:', err);
      }
    };
    window.addEventListener('sb-load-project', handleLoad as EventListener);
    window.addEventListener('sb-force-save', handleForceSave as EventListener);
    return () => {
      window.removeEventListener('sb-load-project', handleLoad as EventListener);
      window.removeEventListener('sb-force-save', handleForceSave as EventListener);
    };
  }, [state, dispatch]);

  // Vertical resize (table ↔ chart)
  useEffect(() => {
    if (resizing !== 'v') return;
    const handleMove = (e: MouseEvent) => {
      const rect = containerRef.current?.getBoundingClientRect();
      if (!rect) return;
      dispatch({ type: 'SET_TABLE_W', width: Math.max(200, Math.min(e.clientX - rect.left, window.innerWidth - 200)) });
    };
    const handleUp = () => { setResizing(null); document.body.style.cursor = ''; document.body.style.userSelect = ''; };
    document.body.style.cursor = 'col-resize';
    document.body.style.userSelect = 'none';
    document.addEventListener('mousemove', handleMove);
    document.addEventListener('mouseup', handleUp);
    return () => { document.removeEventListener('mousemove', handleMove); document.removeEventListener('mouseup', handleUp); };
  }, [resizing]);

  // Horizontal resize (gantt ↔ form)
  useEffect(() => {
    if (resizing !== 'h') return;
    const handleMove = (e: MouseEvent) => {
      const rect = containerRef.current?.getBoundingClientRect();
      if (!rect) return;
      setFormH(Math.max(60, Math.min(rect.bottom - e.clientY, 500)));
    };
    const handleUp = () => { setResizing(null); document.body.style.cursor = ''; document.body.style.userSelect = ''; };
    document.body.style.cursor = 'row-resize';
    document.body.style.userSelect = 'none';
    document.addEventListener('mousemove', handleMove);
    document.addEventListener('mouseup', handleUp);
    return () => { document.removeEventListener('mousemove', handleMove); document.removeEventListener('mouseup', handleUp); };
  }, [resizing]);

  // Keyboard shortcuts
  const handleKeyDown = useCallback((e: KeyboardEvent) => {
    // Check if editing contenteditable or input
    const tgt = e.target as HTMLElement;
    if (tgt.isContentEditable || tgt.tagName === 'INPUT' || tgt.tagName === 'TEXTAREA' || tgt.tagName === 'SELECT') {
      return;
    }
    if (e.key === 'Delete') {
      if (state.selIdx >= 0 && !state.activities[state.selIdx]?._isProjRow) {
        dispatch({ type: 'PUSH_UNDO' });
        dispatch({ type: 'DELETE_ACTIVITY', index: state.selIdx });
      }
    } else if (e.key === 'Insert') {
      dispatch({ type: 'PUSH_UNDO' });
      const a = newActivity(autoId(state.activities), state.defCal);
      a.name = 'Nueva Actividad';
      dispatch({ type: 'ADD_ACTIVITY', activity: a, atIndex: state.selIdx >= 0 ? state.selIdx + 1 : undefined });
    } else if (e.ctrlKey && e.key === 'z') {
      e.preventDefault(); dispatch({ type: 'UNDO' });
    } else if (e.ctrlKey && e.key === 'x') {
      e.preventDefault(); dispatch({ type: 'CUT_ACTIVITY' });
    } else if (e.ctrlKey && e.key === 'c') {
      e.preventDefault(); dispatch({ type: 'COPY_ACTIVITY' });
    } else if (e.ctrlKey && e.key === 'v') {
      e.preventDefault(); dispatch({ type: 'PASTE_ACTIVITY' });
    } else if (e.ctrlKey && e.key === 'ArrowUp') {
      e.preventDefault(); dispatch({ type: 'MOVE_ROW', dir: -1 });
    } else if (e.ctrlKey && e.key === 'ArrowDown') {
      e.preventDefault(); dispatch({ type: 'MOVE_ROW', dir: 1 });
    } else if (e.key === 'ArrowUp' && !e.ctrlKey) {
      if (state.selIdx > 0) { e.preventDefault(); dispatch({ type: 'SET_SELECTION', index: state.selIdx - 1 }); }
    } else if (e.key === 'ArrowDown' && !e.ctrlKey) {
      if (state.selIdx < state.activities.length - 1) { e.preventDefault(); dispatch({ type: 'SET_SELECTION', index: state.selIdx + 1 }); }
    } else if (e.key === 'Escape') {
      dispatch({ type: 'CLOSE_ACT_MODAL' });
      dispatch({ type: 'CLOSE_PROJ_MODAL' });
      dispatch({ type: 'CLOSE_LINK_MODAL' });
      dispatch({ type: 'CLOSE_SB_MODAL' });
      dispatch({ type: 'CLOSE_CAL_MODAL' });
    }
  }, [state.selIdx, state.activities, state.defCal, dispatch]);

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleKeyDown]);

  // Auto-save active portfolio project on window close / refresh
  useEffect(() => {
    const handleBeforeUnload = () => {
      if (pState.activeProjectId && state.activities.length > 0) {
        const snapshot = serializeGanttState(state);
        try { localStorage.setItem('gantt-cpm-project-' + pState.activeProjectId, JSON.stringify(snapshot)); } catch { }
        // Update project metadata
        const tasks = state.activities.filter(a => (a.type === 'task' || a.type === 'milestone') && !a._isProjRow);
        const projRow = state.activities.find(a => a._isProjRow);
        const latestEF = tasks.reduce<Date | null>((max, a) => {
          if (a.EF && (!max || a.EF > max)) return a.EF;
          return max;
        }, null);
        // EF is exclusive (day after last work day), subtract 1 day for display endDate
        const endDateObj = latestEF ? new Date(latestEF.getTime() - 86400000) : null;
        const tw = projRow?.work || 0;
        // Compute actualWork per-task to match project view exactly
        const ew = tasks.reduce((sum, a) => sum + ((a.work || 0) * (a.pct || 0) / 100), 0);
        const meta = pState.projects.map(p => p.id === pState.activeProjectId ? {
          ...p, name: state.projName,
          activityCount: tasks.length,
          completedCount: tasks.filter(a => a.pct === 100).length,
          criticalCount: tasks.filter(a => a.crit).length,
          globalPct: state.progressHistory && state.progressHistory.length > 0
            ? Math.round((state.progressHistory[state.progressHistory.length - 1].actualPct || 0) * 10) / 10
            : (projRow ? Math.round((projRow.pct || 0) * 10) / 10 : 0),
          plannedPct: projRow ? Math.round((projRow._plannedPct || 0) * 10) / 10 : 0,
          startDate: state.projStart ? state.projStart.toISOString() : (p.startDate || null),
          endDate: endDateObj ? endDateObj.toISOString() : (state.projStart ? state.projStart.toISOString() : (p.endDate || null)),
          statusDate: state.statusDate ? state.statusDate.toISOString() : (p.statusDate || null),
          duration: projRow?.dur || p.duration || 0,
          remainingDur: projRow?.remDur || p.remainingDur || 0,
          work: tw || p.work || 0,
          actualWork: Math.round(ew) || p.actualWork || 0,
          remainingWork: Math.round(tw - ew) || p.remainingWork || 0,
          pctProg: projRow ? Math.round((projRow._plannedPct || 0) * 10) / 10 : p.pctProg || 0,
          weight: projRow?.weight ?? p.weight ?? null,
          resources: projRow?.res || p.resources || '',
          updatedAt: new Date().toISOString(),
        } : p);
        try {
          const portfolioData = {
            epsNodes: pState.epsNodes,
            projects: meta,
            expandedIds: Array.from(pState.expandedIds),
            activeProjectId: pState.activeProjectId,
          };
          localStorage.setItem('gantt-cpm-portfolio', JSON.stringify(portfolioData));
        } catch { }
      }
    };
    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [pState, state]);

  const handleModuleChange = useCallback((m: ModuleId) => {
    // Auto-save current project state when navigating away from gantt modules
    if (pState.activeProjectId && state.activities.length > 0) {
      const snapshot = serializeGanttState(state);
      saveProjectState(pState.activeProjectId, snapshot);
      // Update project metadata
      const tasks = state.activities.filter(a => (a.type === 'task' || a.type === 'milestone') && !a._isProjRow);
      const projRow = state.activities.find(a => a._isProjRow);
      const latestEF = tasks.reduce<Date | null>((max, a) => {
        if (a.EF && (!max || a.EF > max)) return a.EF;
        return max;
      }, null);
      // EF is exclusive (day after last work day), subtract 1 day for display endDate
      const endDateObj = latestEF ? new Date(latestEF.getTime() - 86400000) : null;
      const totalWork = projRow?.work || 0;
      // Compute actualWork per-task to match project view exactly
      const earnedWork = tasks.reduce((sum, a) => sum + ((a.work || 0) * (a.pct || 0) / 100), 0);
      pDispatch({
        type: 'UPDATE_PROJECT', id: pState.activeProjectId, updates: {
          name: state.projName,
          activityCount: tasks.length,
          completedCount: tasks.filter(a => a.pct === 100).length,
          criticalCount: tasks.filter(a => a.crit).length,
          globalPct: state.progressHistory && state.progressHistory.length > 0
            ? Math.round((state.progressHistory[state.progressHistory.length - 1].actualPct || 0) * 10) / 10
            : (projRow ? Math.round((projRow.pct || 0) * 10) / 10 : 0),
          plannedPct: projRow ? Math.round((projRow._plannedPct || 0) * 10) / 10 : 0,
          startDate: state.projStart ? state.projStart.toISOString() : null,
          endDate: endDateObj ? endDateObj.toISOString() : (state.projStart ? state.projStart.toISOString() : null),
          statusDate: state.statusDate ? state.statusDate.toISOString() : null,
          supabaseId: localStorage.getItem('sb_current_project_id') || null,
          duration: projRow?.dur || 0,
          remainingDur: projRow?.remDur || 0,
          work: totalWork,
          actualWork: Math.round(earnedWork),
          remainingWork: Math.round(totalWork - earnedWork),
          pctProg: projRow ? Math.round((projRow._plannedPct || 0) * 10) / 10 : 0,
          weight: projRow?.weight ?? null,
          resources: projRow?.res || '',
        }
      });
    }
    setActiveModule(m);
    localStorage.setItem('gantt_active_module', m);
  }, [pState.activeProjectId, state, saveProjectState, pDispatch]);

  // ── Open a project from the portfolio ──
  const handleOpenProject = useCallback(async (projectId: string) => {
    // ── Guard: suppress auto-save while switching projects ──
    switchingProjectRef.current = true;
    if (saveTimeoutRef.current) { clearTimeout(saveTimeoutRef.current); saveTimeoutRef.current = null; }

    // Save current project first if any
    if (pState.activeProjectId && pState.activeProjectId !== projectId && state.activities.length > 0) {
      const snapshot = serializeGanttState(state);
      saveProjectState(pState.activeProjectId, snapshot);
      // Also save to Supabase (fire-and-forget) so data is persisted remotely
      const oldPid = localStorage.getItem('sb_current_project_id');
      if (oldPid) saveToSupabase(state, oldPid).catch(e => console.warn('Save before switch failed:', e));
    }

    const proj = pState.projects.find(p => p.id === projectId);

    // Load the target project
    const saved = loadProjectState(projectId);
    if (saved) {
      // Set Supabase ID BEFORE dispatching to prevent auto-save race
      if (proj?.supabaseId) {
        localStorage.setItem('sb_current_project_id', proj.supabaseId);
      } else {
        localStorage.removeItem('sb_current_project_id');
      }
      restoreDatesFromSaved(saved);
      dispatch({ type: 'LOAD_STATE', state: saved });
    } else if (proj?.supabaseId) {
      // Set Supabase ID BEFORE dispatching to prevent auto-save race
      localStorage.setItem('sb_current_project_id', proj.supabaseId);
      // No local state but project exists in Supabase — load from there
      // ALWAYS reset to a clean state first, then overlay Supabase data.
      const freshName = proj?.name || 'Nuevo Proyecto';
      const freshActs = [
        { ...newActivity('PROY', state.defCal), name: freshName, type: 'summary' as const, lv: -1, _isProjRow: true },
      ];
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      dispatch({ type: 'SET_PROJECT_CONFIG', config: { projName: freshName, projStart: new Date(), defCal: 6 as any, statusDate: new Date() } });
      dispatch({ type: 'SET_ACTIVITIES', activities: freshActs });
      dispatch({ type: 'SET_RESOURCES', resources: [] });
      dispatch({ type: 'SET_PROGRESS_HISTORY', history: [] });
      dispatch({ type: 'SET_PPC_HISTORY', history: [] });
      dispatch({ type: 'SET_LEAN_RESTRICTIONS', restrictions: [] });
      dispatch({ type: 'SET_SCENARIOS', scenarios: [] });
      try {
        const data = await loadFromSupabase(proj.supabaseId);
        // Overlay Supabase data on the clean state (only if project has real data)
        if (data.projName) dispatch({ type: 'SET_PROJECT_CONFIG', config: { projName: data.projName, projStart: data.projStart, defCal: data.defCal, statusDate: data.statusDate || undefined, customFilters: data.customFilters || [], filtersMatchAll: data.filtersMatchAll !== undefined ? data.filtersMatchAll : true } });
        if (data.resourcePool && data.resourcePool.length) dispatch({ type: 'SET_RESOURCES', resources: data.resourcePool });
        if (data.activities && data.activities.length) dispatch({ type: 'SET_ACTIVITIES', activities: data.activities });
        if (data.progressHistory && data.progressHistory.length) dispatch({ type: 'SET_PROGRESS_HISTORY', history: data.progressHistory });
        if (data.ppcHistory && data.ppcHistory.length) dispatch({ type: 'SET_PPC_HISTORY', history: data.ppcHistory });
        if (data.leanRestrictions && data.leanRestrictions.length) dispatch({ type: 'SET_LEAN_RESTRICTIONS', restrictions: data.leanRestrictions });
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        if ((data as any).scenarios && (data as any).scenarios.length) dispatch({ type: 'SET_SCENARIOS', scenarios: (data as any).scenarios });
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        if ((data as any).riskState) dispatch({ type: 'LOAD_RISK_STATE', riskState: (data as any).riskState });
        console.log('Loaded project from Supabase:', proj.supabaseId);
      } catch (err) {
        console.error('Failed to load from Supabase, using fresh state:', err);
      }
    } else {
      // No saved state and no Supabase link — start fresh and auto-create in Supabase
      localStorage.removeItem('sb_current_project_id');
      const freshActs = [
        { ...newActivity('PROY', state.defCal), name: proj?.name || 'Nuevo Proyecto', type: 'summary' as const, lv: -1, _isProjRow: true },
      ];
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      dispatch({ type: 'SET_PROJECT_CONFIG', config: { projName: proj?.name || 'Nuevo Proyecto', projStart: new Date(), defCal: 6 as any, statusDate: new Date() } });
      dispatch({ type: 'SET_ACTIVITIES', activities: freshActs });
      dispatch({ type: 'SET_RESOURCES', resources: [] });
      dispatch({ type: 'SET_PROGRESS_HISTORY', history: [] });
      dispatch({ type: 'SET_PPC_HISTORY', history: [] });
      dispatch({ type: 'SET_LEAN_RESTRICTIONS', restrictions: [] });
      dispatch({ type: 'SET_SCENARIOS', scenarios: [] });
      // Auto-create in Supabase so auto-save works immediately
      if (proj) {
        try {
          const sbId = await createSupabaseProject(proj.name);
          localStorage.setItem('sb_current_project_id', sbId);
          pDispatch({ type: 'UPDATE_PROJECT', id: projectId, updates: { supabaseId: sbId } });
        } catch (err) {
          console.warn('Failed to create Supabase project:', err);
        }
      }
    }

    pDispatch({ type: 'SET_ACTIVE_PROJECT', id: projectId });
    setActiveModule('gantt');
    localStorage.setItem('gantt_active_module', 'gantt');

    // ── Release auto-save guard after a short delay to let React batched dispatches settle ──
    setTimeout(() => { switchingProjectRef.current = false; }, 1200);
  }, [pState.activeProjectId, pState.projects, state, saveProjectState, loadProjectState, dispatch, pDispatch]);

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100vh', overflow: 'hidden' }}>
      {/* ── Module Tabs ── */}
      <ModuleTabs active={activeModule} onChange={handleModuleChange} activeProjectName={pState.activeProjectId ? (pState.projects.find(p => p.id === pState.activeProjectId)?.name || null) : null} hasActiveProject={hasActiveProject} />

      {/* ── Module: Inicio ── */}
      {activeModule === 'inicio' && <div style={{ display: 'flex', flexDirection: 'column', flex: 1, minHeight: 0, overflow: 'hidden' }}><InicioPage onNavigate={handleModuleChange} /></div>}

      {/* ── Module: Proyectos (Portfolio) ── */}
      {activeModule === 'projects' && <div style={{ display: 'flex', flexDirection: 'column', flex: 1, minHeight: 0, overflow: 'hidden' }}><ProjectsPage onNavigate={handleModuleChange} onOpenProject={handleOpenProject} /></div>}

      {/* ── Module: Look Ahead ── */}
      {activeModule === 'lookAhead' && <div style={{ display: 'flex', flexDirection: 'column', flex: 1, minHeight: 0, overflow: 'hidden' }}><LookAheadPage /></div>}

      {/* ── Module: Dashboard ── */}
      {activeModule === 'dashboard' && <div style={{ display: 'flex', flexDirection: 'column', flex: 1, minHeight: 0, overflow: 'hidden' }}><DashboardPage /></div>}

      {/* ── Module: Configuración ── */}
      {activeModule === 'config' && <div style={{ display: 'flex', flexDirection: 'column', flex: 1, minHeight: 0, overflow: 'hidden' }}><ConfigPage /></div>}

      {/* ── Module: What-If Scenarios ── */}
      {activeModule === 'whatIf' && <div style={{ display: 'flex', flexDirection: 'column', flex: 1, minHeight: 0, overflow: 'hidden' }}><WhatIfPage /></div>}

      {/* ── Module: Risk Analysis / Monte Carlo ── */}
      {activeModule === 'risk' && <div style={{ display: 'flex', flexDirection: 'column', flex: 1, minHeight: 0, overflow: 'hidden' }}><RiskAnalysisPage /></div>}

      {/* ── Module: Carta Gantt (existing) ── */}
      {activeModule === 'gantt' && (<>
        <Ribbon />

        {state.currentView === 'resources' ? (
          <div style={{ flex: 1, overflow: 'hidden' }}>
            <ResourceSheet />
          </div>
        ) : state.currentView === 'wbs' ? (
          <div style={{ flex: 1, overflow: 'hidden' }}>
            <WBSOrgChartView
              activities={state.activities}
              selectedId={state.activities[state.selIdx]?.id ?? null}
              onSelect={id => {
                const idx = state.activities.findIndex(a => a.id === id);
                if (idx >= 0) dispatch({ type: 'SET_SELECTION', index: idx });
              }}
              projectName={state.projName}
            />
          </div>
        ) : state.currentView === 'scurve' ? (
          <div style={{ flex: 1, overflow: 'hidden' }}>
            <SCurveChart />
          </div>
        ) : state.currentView === 'usage' ? (
          <div ref={containerRef} style={{ display: 'flex', flexDirection: 'column', flex: 1, overflow: 'hidden' }}>
            {/* Usage Area (Table | Resize | Grid) */}
            <div style={{ display: 'flex', flex: 1, minHeight: 0, overflow: 'hidden' }}>
              {/* Table */}
              <div style={{ width: state.tableW, flexShrink: 0, overflow: 'hidden' }}>
                <GanttTable />
              </div>

              {/* Vertical Resize Handle */}
              <div className={`v-resize ${resizing === 'v' ? 'rsz' : ''}`}
                onMouseDown={() => setResizing('v')} />

              {/* Usage Grid */}
              <div style={{ flex: 1, overflow: 'hidden' }}>
                <TaskUsageGrid />
              </div>
            </div>

            {/* Horizontal Resize Handle */}
            <div className={`h-resize ${resizing === 'h' ? 'rsz' : ''}`}
              onMouseDown={() => setResizing('h')} />

            {/* Form Panel */}
            <div style={{ height: formH, flexShrink: 0, overflow: 'hidden' }}>
              <TaskForm />
            </div>
          </div>
        ) : state.currentView === 'resUsage' ? (
          <div ref={containerRef} style={{ display: 'flex', flexDirection: 'column', flex: 1, overflow: 'hidden' }}>
            {/* Resource Usage Area (Table | Resize | Grid) */}
            <div style={{ display: 'flex', flex: 1, minHeight: 0, overflow: 'hidden' }}>
              {/* Table */}
              <div style={{ width: state.tableW, flexShrink: 0, overflow: 'hidden' }}>
                <ResourceUsageTable />
              </div>

              {/* Vertical Resize Handle */}
              <div className={`v-resize ${resizing === 'v' ? 'rsz' : ''}`}
                onMouseDown={() => setResizing('v')} />

              {/* Usage Grid */}
              <div style={{ flex: 1, overflow: 'hidden' }}>
                <ResourceUsageGrid />
              </div>
            </div>

            {/* Horizontal Resize Handle */}
            <div className={`h-resize ${resizing === 'h' ? 'rsz' : ''}`}
              onMouseDown={() => setResizing('h')} />

            {/* Form Panel */}
            <div style={{ height: formH, flexShrink: 0, overflow: 'hidden' }}>
              <ResourceForm />
            </div>
          </div>
        ) : (
          <div ref={containerRef} style={{ display: 'flex', flexDirection: 'column', flex: 1, overflow: 'hidden' }}>
            {/* Gantt Area (Table | Resize | Timeline) */}
            <div style={{ display: 'flex', flex: 1, minHeight: 0, overflow: 'hidden' }}>
              {/* Table */}
              <div style={{ width: state.tableW, flexShrink: 0, overflow: 'hidden' }}>
                <GanttTable />
              </div>

              {/* Vertical Resize Handle */}
              <div className={`v-resize ${resizing === 'v' ? 'rsz' : ''}`}
                onMouseDown={() => setResizing('v')} />

              {/* Timeline */}
              <div style={{ flex: 1, overflow: 'hidden' }}>
                <GanttTimeline />
              </div>
            </div>

            {/* Horizontal Resize Handle */}
            <div className={`h-resize ${resizing === 'h' ? 'rsz' : ''}`}
              onMouseDown={() => setResizing('h')} />

            {/* Form Panel */}
            <div style={{ height: formH, flexShrink: 0, overflow: 'hidden' }}>
              <ActivityDetailPanel />
            </div>
          </div>
        )}
      </>)}

      {/* Modals */}
      <ActivityModal />
      <ProjectModal />
      {/* Suppress LinkModal when a what-if scenario is active — WhatIfPage renders its own inside ScenarioGanttProvider */}
      {!(activeModule === 'whatIf' && state.activeScenarioId) && <LinkModal />}
      <SupabaseModal />
      <SaveProgressModal />
      <BaselineModal />
      <CalendarModal />
      <CheckThresholdsModal />
      <FilterModal />

      {/* PASSWORD RECOVERY MODAL */}
      {showRecoveryModal && (
        <div className="modal-overlay" style={{ zIndex: 9999 }}>
          <div className="modal-content" style={{ maxWidth: 400, padding: '2rem' }}>
            <h3 style={{ marginBottom: '1rem', color: 'var(--text-color)' }}>Restablecer Contraseña</h3>
            <p style={{ marginBottom: '1rem', color: 'var(--text-muted)' }}>Introduce tu nueva contraseña para acceder a tu cuenta.</p>
            <form onSubmit={handleUpdatePassword} style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
              <input
                type="password"
                placeholder="Nueva contraseña"
                value={newRecoveryPassword}
                onChange={e => setNewRecoveryPassword(e.target.value)}
                required
                style={{ padding: '0.8rem', border: '1px solid var(--border-color)', borderRadius: '4px', backgroundColor: 'var(--bg-color)', color: 'var(--text-color)' }}
              />
              <button type="submit" disabled={recoveryLoading} style={{ padding: '0.8rem', backgroundColor: '#0078d4', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer', fontWeight: 600 }}>
                {recoveryLoading ? 'Actualizando...' : 'Actualizar Contraseña'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
function AppRoot() {
  const { session, loading, error, signOut } = useAuth();

  if (error) {
    return (
      <div style={{ height: '100vh', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', color: 'var(--text-color)', backgroundColor: 'var(--bg-color)', padding: '2rem', textAlign: 'center' }}>
        <h2 style={{ color: '#ff4d4f', marginBottom: '1rem' }}>Error de Sesión</h2>
        <p style={{ marginBottom: '2rem' }}>{error}</p>
        <button
          onClick={async () => {
            try { await signOut(); } catch (e) { }
            localStorage.clear();
            sessionStorage.clear();
            window.location.reload();
          }}
          style={{ padding: '0.5rem 1rem', background: '#0078d4', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer' }}
        >
          Forzar Cierre de Sesión
        </button>
      </div>
    );
  }

  if (loading) {
    return <div style={{ height: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-color)', backgroundColor: 'var(--bg-color)' }}>Cargando sesión...</div>;
  }

  if (!session) {
    return <LoginPage />;
  }

  return (
    <PortfolioProvider>
      <GanttProvider>
        <AppInner />
      </GanttProvider>
    </PortfolioProvider>
  );
}

export default function App() {
  return (
    <AuthProvider>
      <AppRoot />
    </AuthProvider>
  );
}

// ═══════════════════════════════════════════════════════════════════
// Project Configuration Modal – matches HTML #modal-overlay exactly
// ═══════════════════════════════════════════════════════════════════
import { useState, useEffect } from 'react';
import { useGantt } from '../../store/GanttContext';
import { isoDate, parseDate } from '../../utils/cpm';

export default function ProjectModal() {
    const { state, dispatch } = useGantt();
    const [form, setForm] = useState({ name: '', start: '', status: '', cal: '6' });

    useEffect(() => {
        if (state.projModalOpen) {
            setForm({
                name: state.projName,
                start: isoDate(state.projStart),
                status: isoDate(state.statusDate),
                cal: String(state.defCal),
            });
        }
    }, [state.projModalOpen]);

    if (!state.projModalOpen) return null;

    const save = () => {
        interface ProjectConfigMap { projName?: string; projStart?: Date; statusDate?: Date; defCal?: string | number; }
        const config: ProjectConfigMap = {};
        config.projName = form.name || 'Mi Proyecto';
        const d = parseDate(form.start);
        if (d) config.projStart = d;
        const sd = parseDate(form.status);
        if (sd) config.statusDate = sd;
        config.defCal = isNaN(parseInt(form.cal)) ? form.cal : (parseInt(form.cal) || 6);
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        dispatch({ type: 'SET_PROJECT_CONFIG', config: config as any });
        dispatch({ type: 'CLOSE_PROJ_MODAL' });
    };

    const close = () => dispatch({ type: 'CLOSE_PROJ_MODAL' });
    const F = (key: string, val: string) => setForm(f => ({ ...f, [key]: val }));

    return (
        <div className="modal-overlay open" onClick={e => { if (e.target === e.currentTarget) close(); }}>
            <div className="modal" style={{ width: 420 }}>
                <h2>Configuración del Proyecto</h2>
                <div className="form-group"><label className="form-label">Nombre del Proyecto</label>
                    <input className="form-input" value={form.name} onChange={e => F('name', e.target.value)} />
                </div>
                <div className="form-row">
                    <div className="form-group"><label className="form-label">Fecha de Inicio</label>
                        <input className="form-input" type="date" value={form.start} onChange={e => F('start', e.target.value)} />
                    </div>
                    <div className="form-group"><label className="form-label">Fecha de Corte (Status)</label>
                        <input className="form-input" type="date" value={form.status} onChange={e => F('status', e.target.value)} />
                        <div style={{ fontSize: '10px', color: '#64748b', marginTop: 4, lineHeight: 1.2 }}>
                            Nota: Se evalúa al final del día (jornada completa).
                        </div>
                    </div>
                </div>
                <div className="form-group"><label className="form-label">Calendario por Defecto</label>
                    <select className="form-input" value={form.cal} onChange={e => F('cal', e.target.value)}>
                        <option value="5">5 días - Lunes a Viernes</option>
                        <option value="6">6 días - Lunes a Sábado</option>
                        <option value="7">7 días - Continuo</option>
                        {state.customCalendars.map(cc => (
                            <option key={cc.id} value={cc.id}>{cc.name}</option>
                        ))}
                    </select>
                </div>
                <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end', marginTop: 14 }}>
                    <button className="btn btn-ghost" onClick={close}>Cancelar</button>
                    <button className="btn btn-primary" onClick={save}>Guardar</button>
                </div>
            </div>
        </div>
    );
}

// OrgChartView.tsx – Clean EPS-only hierarchy tree
// Shows only EPS structural nodes (no projects/activities)
import React, { useMemo, useState, useRef, useCallback, useEffect } from 'react';
import type { EPSNode } from '../../types/portfolio';

// ── Layout constants ─────────────────────────────────────────────
const BOX_W = 200;
const BOX_H = 88;
const H_GAP = 36;    // horizontal gap between siblings
const V_GAP = 80;    // vertical gap between levels

// ── Internal node type ───────────────────────────────────────────
interface ChartNode {
    eps: EPSNode;
    children: ChartNode[];
    // filled during layout
    x: number;      // center x
    y: number;      // top y
    subtreeW: number;
}

// ── Build tree from flat EPS list ────────────────────────────────
function buildTree(epsNodes: EPSNode[], collapsedSet: Set<string>): ChartNode[] {
    const map = new Map<string, ChartNode>();
    for (const e of epsNodes) {
        map.set(e.id, { eps: e, children: [], x: 0, y: 0, subtreeW: BOX_W });
    }
    const roots: ChartNode[] = [];
    for (const e of epsNodes) {
        const node = map.get(e.id)!;
        if (e.parentId && map.has(e.parentId)) {
            map.get(e.parentId)!.children.push(node);
        } else {
            roots.push(node);
        }
    }
    // Sort children by order field
    function sortChildren(n: ChartNode) {
        n.children.sort((a, b) => (a.eps.order ?? 0) - (b.eps.order ?? 0));
        if (!collapsedSet.has(n.eps.id)) n.children.forEach(sortChildren);
        else n.children = []; // collapsed → treat as leaf visually
    }
    roots.sort((a, b) => (a.eps.order ?? 0) - (b.eps.order ?? 0));
    roots.forEach(sortChildren);
    return roots;
}

// ── Layout: Reingold-Tilford-style centering ─────────────────────
function computeLayout(nodes: ChartNode[], startX = 0, startY = 0): void {
    function measure(node: ChartNode): number {
        if (!node.children.length) {
            node.subtreeW = BOX_W;
            return BOX_W;
        }
        let total = 0;
        for (const child of node.children) {
            total += measure(child);
            total += H_GAP;
        }
        total -= H_GAP;
        node.subtreeW = Math.max(BOX_W, total);
        return node.subtreeW;
    }

    function position(node: ChartNode, baseX: number, baseY: number) {
        node.x = baseX + node.subtreeW / 2;
        node.y = baseY;
        if (!node.children.length) return;
        let cx = baseX + (node.subtreeW - (node.children.reduce((s, c) => s + c.subtreeW, 0) + H_GAP * (node.children.length - 1))) / 2;
        for (const child of node.children) {
            position(child, cx, baseY + BOX_H + V_GAP);
            cx += child.subtreeW + H_GAP;
        }
    }

    let cx = startX;
    for (const root of nodes) {
        measure(root);
        position(root, cx, startY);
        cx += root.subtreeW + H_GAP;
    }
}

// ── Flatten for rendering ────────────────────────────────────────
interface FlatItem { node: ChartNode; parentNode?: ChartNode }
function flatten(nodes: ChartNode[], parent?: ChartNode): FlatItem[] {
    const result: FlatItem[] = [];
    for (const n of nodes) {
        result.push({ node: n, parentNode: parent });
        result.push(...flatten(n.children, n));
    }
    return result;
}

// ═══════════════════════════════════════════════════════
// MAIN COMPONENT
// ═══════════════════════════════════════════════════════
interface Props {
    epsNodes: EPSNode[];
    selectedId: string | null;
    onSelect: (id: string) => void;
}

export default function OrgChartView({ epsNodes, selectedId, onSelect }: Props) {
    const containerRef = useRef<HTMLDivElement>(null);
    const [collapsed, setCollapsed] = useState<Set<string>>(new Set());
    const [scale, setScale] = useState(0.85);
    const [pan, setPan] = useState({ x: 60, y: 60 });
    const dragging = useRef(false);
    const dragStart = useRef({ mx: 0, my: 0, px: 0, py: 0 });

    const roots = useMemo(() => {
        const tree = buildTree(epsNodes, collapsed);
        computeLayout(tree, 0, 0);
        return tree;
    }, [epsNodes, collapsed]);

    const items = useMemo(() => flatten(roots), [roots]);

    // Compute svg canvas size
    const [svgW, svgH] = useMemo(() => {
        if (!items.length) return [800, 400];
        const maxX = Math.max(...items.map(i => i.node.x + BOX_W / 2));
        const maxY = Math.max(...items.map(i => i.node.y + BOX_H));
        return [maxX + 60, maxY + 60];
    }, [items]);

    // Auto-center on data change
    useEffect(() => {
        if (!containerRef.current || !items.length) return;
        const cW = containerRef.current.clientWidth;
        const cH = containerRef.current.clientHeight;
        const margin = 60;
        const fitScale = Math.min(1.3, Math.min((cW - margin * 2) / svgW, (cH - margin * 2) / svgH));
        const newScale = Math.max(0.2, fitScale);
        const scaledW = svgW * newScale;
        const scaledH = svgH * newScale;
        setScale(newScale);
        setPan({ x: (cW - scaledW) / 2, y: (cH - scaledH) / 2 });
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [epsNodes.length]);

    const resetView = useCallback(() => {
        if (!containerRef.current || !items.length) return;
        const cW = containerRef.current.clientWidth;
        const cH = containerRef.current.clientHeight;
        const margin = 60;
        const fitScale = Math.min(1.3, Math.min((cW - margin * 2) / svgW, (cH - margin * 2) / svgH));
        const newScale = Math.max(0.2, fitScale);
        const scaledW = svgW * newScale;
        const scaledH = svgH * newScale;
        setScale(newScale);
        setPan({ x: (cW - scaledW) / 2, y: (cH - scaledH) / 2 });
    }, [items.length, svgW, svgH]);

    const toggleCollapse = useCallback((id: string, e: React.MouseEvent) => {
        e.stopPropagation();
        setCollapsed(prev => { const n = new Set(prev); n.has(id) ? n.delete(id) : n.add(id); return n; });
    }, []);

    // Pan
    const onMouseDown = useCallback((e: React.MouseEvent) => {
        if ((e.target as SVGElement).closest('.eps-node')) return;
        dragging.current = true;
        dragStart.current = { mx: e.clientX, my: e.clientY, px: pan.x, py: pan.y };
    }, [pan]);
    const onMouseMove = useCallback((e: React.MouseEvent) => {
        if (!dragging.current) return;
        setPan({ x: dragStart.current.px + e.clientX - dragStart.current.mx, y: dragStart.current.py + e.clientY - dragStart.current.my });
    }, []);
    const onMouseUp = useCallback(() => { dragging.current = false; }, []);
    const onWheel = useCallback((e: React.WheelEvent) => {
        e.preventDefault();
        setScale(s => Math.min(Math.max(s * (e.deltaY > 0 ? 0.88 : 1.14), 0.1), 4));
    }, []);

    if (!epsNodes.length) {
        return (
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%', color: 'var(--text-muted)', flexDirection: 'column', gap: 10 }}>
                <span style={{ fontSize: 40, opacity: 0.15 }}>🗂</span>
                <p style={{ fontSize: 13, margin: 0 }}>Sin estructura EPS definida</p>
                <p style={{ fontSize: 11, margin: 0, opacity: 0.6 }}>Cree carpetas EPS con el botón "EPS" en la barra de herramientas</p>
            </div>
        );
    }

    return (
        <div
            ref={containerRef}
            style={{
                width: '100%', height: '100%', overflow: 'hidden',
                background: 'var(--bg-main)',
                cursor: 'grab', position: 'relative', userSelect: 'none',
            }}
            onMouseDown={onMouseDown}
            onMouseMove={onMouseMove}
            onMouseUp={onMouseUp}
            onMouseLeave={onMouseUp}
            onWheel={onWheel}
        >
            {/* ── Controls ── */}
            <div style={{ position: 'absolute', top: 10, right: 10, zIndex: 20, display: 'flex', flexDirection: 'column', gap: 3 }}>
                {[
                    { label: '+', action: () => setScale(s => Math.min(s * 1.2, 4)) },
                    { label: '−', action: () => setScale(s => Math.max(s * 0.83, 0.1)) },
                    { label: '↺', action: resetView },
                ].map(b => (
                    <button key={b.label} onClick={b.action} style={{
                        width: 28, height: 28, borderRadius: 6,
                        background: 'rgba(15,23,42,0.85)', backdropFilter: 'blur(4px)',
                        border: '1px solid rgba(99,102,241,0.3)',
                        color: '#e2e8f0', cursor: 'pointer', fontSize: 15, fontWeight: 700,
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        boxShadow: '0 2px 8px rgba(0,0,0,0.4)',
                    }}>{b.label}</button>
                ))}
            </div>

            {/* ── Legend ── */}
            <div style={{ position: 'absolute', bottom: 12, left: 12, zIndex: 20, display: 'flex', alignItems: 'center', gap: 10, padding: '5px 10px', background: 'rgba(15,23,42,0.7)', borderRadius: 6, backdropFilter: 'blur(4px)', border: '1px solid rgba(255,255,255,0.06)' }}>
                <div style={{ width: 12, height: 12, background: '#f59e0b', borderRadius: 2, opacity: 0.8 }} />
                <span style={{ fontSize: 11, color: '#94a3b8' }}>EPS – Estructura de carpetas del portfolio</span>
                <span style={{ fontSize: 10, color: '#475569', marginLeft: 6 }}>Doble clic: colapsar/expandir | Rueda: zoom | Arrastrar: mover</span>
            </div>

            {/* ── Scale indicator ── */}
            <div style={{ position: 'absolute', bottom: 12, right: 10, zIndex: 20, fontSize: 10, color: '#475569' }}>
                {Math.round(scale * 100)}%
            </div>

            <svg
                width="100%" height="100%"
                style={{ display: 'block', position: 'absolute', inset: 0 }}
            >
                <defs>
                    <filter id="cardShadow" x="-10%" y="-10%" width="120%" height="130%">
                        <feDropShadow dx="0" dy="3" stdDeviation="4" floodColor="rgba(0,0,0,0.45)" />
                    </filter>
                    <filter id="cardShadowSel" x="-10%" y="-10%" width="120%" height="130%">
                        <feDropShadow dx="0" dy="0" stdDeviation="6" floodColor="rgba(245,158,11,0.6)" />
                    </filter>
                </defs>

                <g transform={`translate(${pan.x},${pan.y}) scale(${scale})`}>

                    {/* ── Connector lines ── */}
                    {items.filter(i => i.parentNode).map(({ node, parentNode }) => {
                        const px = parentNode!.x;
                        const py = parentNode!.y + BOX_H;
                        const cx = node.x;
                        const cy = node.y;
                        const midY = py + V_GAP / 2;
                        const isSel = node.eps.id === selectedId || parentNode!.eps.id === selectedId;
                        return (
                            <path
                                key={node.eps.id + '-conn'}
                                d={`M ${px} ${py} L ${px} ${midY} L ${cx} ${midY} L ${cx} ${cy}`}
                                fill="none"
                                stroke={isSel ? 'rgba(245,158,11,0.8)' : 'rgba(148,163,184,0.22)'}
                                strokeWidth={isSel ? 2 : 1.5}
                                strokeLinecap="round"
                                strokeLinejoin="round"
                            />
                        );
                    })}

                    {/* ── EPS Nodes ── */}
                    {items.map(({ node }) => {
                        const { eps } = node;
                        const left = node.x - BOX_W / 2;
                        const top = node.y;
                        const isSel = eps.id === selectedId;
                        const hasChildren = node.children.length > 0 || epsNodes.some(e => e.parentId === eps.id);
                        const isCollapsed = collapsed.has(eps.id);
                        const depth = eps.parentId
                            ? (epsNodes.find(e => e.id === eps.parentId)?.parentId ? 2 : 1)
                            : 0;

                        // Accent color varies by depth
                        const accentColors = ['#f59e0b', '#fb923c', '#facc15'];
                        const accent = eps.color || accentColors[Math.min(depth, 2)];
                        const bgFill = isSel ? 'rgba(245,158,11,0.18)' : 'rgba(15,23,42,0.92)';

                        return (
                            <g
                                key={eps.id}
                                className="eps-node"
                                transform={`translate(${left},${top})`}
                                onClick={() => onSelect(eps.id)}
                                onDoubleClick={e => toggleCollapse(eps.id, e)}
                                style={{ cursor: 'pointer' }}
                            >
                                {/* Card */}
                                <rect
                                    width={BOX_W} height={BOX_H} rx={8} ry={8}
                                    fill={bgFill}
                                    stroke={isSel ? accent : 'rgba(255,255,255,0.08)'}
                                    strokeWidth={isSel ? 2 : 1}
                                    filter={isSel ? 'url(#cardShadowSel)' : 'url(#cardShadow)'}
                                />

                                {/* Left accent bar */}
                                <rect x={0} y={0} width={4} height={BOX_H} rx={8} ry={8} fill={accent} opacity={0.85} />
                                <rect x={0} y={8} width={4} height={BOX_H - 16} fill={accent} opacity={0.85} />

                                {/* Header background stripe */}
                                <rect x={4} y={0} width={BOX_W - 4} height={24} rx={0} ry={0} fill={`${accent}18`} />
                                <rect x={4} y={0} width={BOX_W - 4} height={24}
                                    style={{ borderTopRightRadius: 8, clipPath: 'inset(0 0 0 0 round 0 8px 0 0)' }}
                                    fill="none" />

                                {/* EPS Code */}
                                <text
                                    x={14} y={15}
                                    fontSize={11} fontWeight={800}
                                    fill={accent}
                                    dominantBaseline="middle"
                                    style={{ fontFamily: '"JetBrains Mono", monospace', letterSpacing: 0.5 }}
                                >
                                    {eps.epsCode || eps.id.slice(0, 8)}
                                </text>

                                {/* Name */}
                                <foreignObject x={10} y={26} width={BOX_W - 20} height={36}>
                                    <div
                                        style={{
                                            fontSize: 11,
                                            color: isSel ? '#f8fafc' : '#cbd5e1',
                                            lineHeight: 1.3,
                                            overflow: 'hidden',
                                            display: '-webkit-box',
                                            WebkitLineClamp: 2,
                                            WebkitBoxOrient: 'vertical',
                                            wordBreak: 'break-word',
                                            fontFamily: 'Inter, system-ui, sans-serif',
                                        } as React.CSSProperties}
                                    >
                                        {eps.name}
                                    </div>
                                </foreignObject>

                                {/* Sub-EPS count + depth info */}
                                <line x1={10} y1={65} x2={BOX_W - 10} y2={65} stroke="rgba(255,255,255,0.06)" strokeWidth={1} />
                                <text x={14} y={76} fontSize={8} fill="#64748b" dominantBaseline="middle">
                                    <tspan fontWeight={600} fill="#475569">Sub-EPS:</tspan> {epsNodes.filter(e => e.parentId === eps.id).length}  ·  <tspan fontWeight={600} fill="#475569">Nivel:</tspan> {depth}
                                </text>

                                {/* Collapse/Expand button */}
                                {hasChildren && (
                                    <g
                                        transform={`translate(${BOX_W / 2}, ${BOX_H + 1})`}
                                        onClick={e => toggleCollapse(eps.id, e)}
                                        style={{ cursor: 'pointer' }}
                                    >
                                        <circle r={9} fill="rgba(15,23,42,0.95)" stroke={accent} strokeWidth={1.5} />
                                        <text
                                            textAnchor="middle"
                                            dominantBaseline="middle"
                                            fill={accent}
                                            fontSize={13}
                                            fontWeight={900}
                                            y={0.5}
                                        >
                                            {isCollapsed ? '+' : '−'}
                                        </text>
                                    </g>
                                )}
                            </g>
                        );
                    })}
                </g>
            </svg>
        </div>
    );
}

// ═══════════════════════════════════════════════════════════════════
// PPCPanel – Percent Plan Complete & Root-Cause Analysis
//
// Last Planner System core metrics:
// 1. PPC (Porcentaje de Plan Cumplido) — weekly reliability measure
// 2. Efficiency — programmed % vs real % achieved
// 3. CNC (Causas de No Cumplimiento) — root-cause Pareto analysis
import React, { useState, useMemo, useRef, useEffect, useCallback } from 'react';
import { useGantt } from '../../store/GanttContext';
import type { PPCWeekRecord, CNCEntry, CNCCategory, ProgressHistoryEntry, BaselineEntry } from '../../types/gantt';
import { isoDate, fmtDate, parseDate, getExactElapsedRatio, getExactWorkDays } from '../../utils/cpm';
import { BarChart3, PlusCircle, Trash2, CalendarDays, TrendingUp, Award, Activity, Search, CheckSquare, Square, Edit2, AlertTriangle } from 'lucide-react';
/** Get the planned % at a specific date (0-100) using two-segment baseline interpolation
 *  (matches LookAheadGrid logic: if baseline had progress at save-time, interpolates in two segments) */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
function getPlannedPctAt(
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  a: { blES: Date | null; blEF: Date | null; ES: Date | null; EF: Date | null; cal: any; baselines?: BaselineEntry[] },
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  target: Date, defCal: any, activeBlIdx: number
): number {
  const start = a.blES || a.ES;
  const end = a.blEF || a.EF;
  if (!start || !end) return 0;
  const stObj = new Date(start); stObj.setHours(0, 0, 0, 0);
  const endObj = new Date(end); endObj.setHours(0, 0, 0, 0);
  if (target <= stObj) return 0;
  if (target >= endObj) return 100;
  const cal = a.cal || defCal;
  const activeBl = (a.baselines || [])[activeBlIdx] || null;
  if (activeBl && activeBl.pct != null && activeBl.statusDate) {
    const blPct = activeBl.pct;
    if (blPct === 0) return getExactElapsedRatio(start, end, target, cal) * 100;
    const blStatusEnd = new Date(activeBl.statusDate); blStatusEnd.setHours(0, 0, 0, 0);
    blStatusEnd.setDate(blStatusEnd.getDate() + 1);
    if (target <= blStatusEnd) {
      const totalWdSeg1 = getExactWorkDays(stObj, blStatusEnd, cal);
      const elapsedWd = getExactWorkDays(stObj, target <= stObj ? stObj : new Date(target), cal);
      const ratioSeg1 = totalWdSeg1 > 0 ? elapsedWd / totalWdSeg1 : 1;
      return ratioSeg1 * blPct;
    } else {
      const totalWdSeg2 = getExactWorkDays(blStatusEnd, endObj, cal);
      const elapsedWd = getExactWorkDays(blStatusEnd, new Date(target), cal);
      const ratioSeg2 = totalWdSeg2 > 0 ? elapsedWd / totalWdSeg2 : 1;
      return blPct + ratioSeg2 * (100 - blPct);
    }
  }
  return getExactElapsedRatio(start, end, target, cal) * 100;
}

/** Get the real % for an activity at a specific date from progressHistory (closest entry ≤ date) */
function getRealPctAt(actId: string, targetISO: string, sortedHistory: ProgressHistoryEntry[]): number {
  // sortedHistory must be ascending by date
  let best = 0;
  for (const entry of sortedHistory) {
    if (entry.date > targetISO) break;
    if (entry.snapshots?.[actId]) best = entry.snapshots[actId].pct;
    else if (entry.details?.[actId] != null) best = entry.details[actId];
  }
  return best;
}

const CNC_CATEGORIES: CNCCategory[] = [
